/* Basic block counting optimization pass for GCC.
   This pass demonstrates a minimal GIMPLE optimization pass
   that counts the number of basic blocks in each function.

   Copyright (C) 2026 Free Software Foundation, Inc.

This file is part of GCC.

GCC is free software; you can redistribute it and/or modify it
under the terms of the GNU General Public License as published by the
Free Software Foundation; either version 3, or (at your option) any
later version.

GCC is distributed in the hope that it will be useful, but WITHOUT
ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or
FITNESS FOR A PARTICULAR PURPOSE.  See the GNU General Public License
for more details.

You should have received a copy of the GNU General Public License
along with GCC; see the file COPYING3.  If not see
<http://www.gnu.org/licenses/>.  */

/* This pass counts the number of basic blocks in each function
   and outputs the result to the dump file.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "tree-cfg.h"
#include "basic-block.h"
#include "dumpfile.h"

namespace
{

/* Pass data for the block counter pass.  */
const pass_data pass_data_block_counter
  = {
    GIMPLE_PASS,        /* type */
    "block_counter",    /* name */
    OPTGROUP_NONE,      /* optinfo_flags */
    TV_NONE,            /* tv_id */
    (PROP_cfg),         /* properties_required */
    0,                  /* properties_provided */
    0,                  /* properties_destroyed */
    0,                  /* todo_flags_start */
    0,                  /* todo_flags_finish */
  };

/* Basic block counter GIMPLE pass.  */
class pass_block_counter : public gimple_opt_pass
{
public:
  pass_block_counter (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_block_counter, ctxt)
  {
  }

  /* opt_pass methods: */
  opt_pass *clone () final override
  {
    return new pass_block_counter (m_ctxt);
  }

  bool gate (function *) final override
  {
    /* This pass always runs when CFG is available.  */
    return true;
  }

  unsigned int execute (function *fun) final override
  {
    /* Count basic blocks in this function.  */
    unsigned int block_count = 0;
    basic_block bb;

    /* Iterate over all basic blocks in the function using FOR_EACH_BB_FN.  */
    FOR_EACH_BB_FN (bb, fun)
    {
      block_count++;
    }

    /* Output the count to dump file if available.  */
    if (dump_file)
    {
      fprintf (dump_file, "Function '%s' has %u basic blocks\n",
               function_name (fun), block_count);
    }

    /* Return 0 to indicate no changes were made.  */
    return 0;
  }
}; /* class pass_block_counter */

} /* anon namespace */

/* Factory function to create an instance of the block counter pass.  */
gimple_opt_pass *
make_pass_block_counter (gcc::context *ctxt)
{
  return new pass_block_counter (ctxt);
}

